  const idempotencyKey = req.headers['x-idempotency-key'];
  if (!idempotencyKey) return res.status(400).send('Key missing');

  const cachedResult = await redis.get(idempotencyKey);
  if (cachedResult) return res.json(JSON.parse(cachedResult));

  const payment = await db.createPayment(req.body);
  await redis.set(idempotencyKey, JSON.stringify(payment), 'EX', 86400);
  res.status(201).json(payment);
});

async function isRateLimited(userId) {
  const key = `rate:${userId}`;
  const requests = await redis.incr(key);
  if (requests === 1) {
    await redis.expire(key, 60);
  }
  return requests > 100; // Limit to 100 requests per minute
}

